//            fs_102_01_16p(거래명세서번호 검색) - 거래명세서번호 조회 버튼 클릭
//==================================================================================================================
scwin.vCurDate;
scwin.vQryStDt;
scwin.vQryEndDt;

scwin.onpageload = function() {
    const codeOptions = [
        { grpCd : "FS261", compID : "acb_copCoConfirmClsCd" },
        { grpCd : "FS262", compID : "acb_pchsAdmitClsCd" }
    ];
    $c.data.setCommonCode(codeOptions, scwin.codeSetCommonCodeCallBack);

    scwin.vCurDate = $c.date.getServerDateTime("yyyyMMdd");  // 서버를 기준으로 현재 날짜 반환
	scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
	scwin.vQryEndDt = scwin.vCurDate.substring(0, 6) + $c.date.getLastDateOfMonth(scwin.vCurDate.substring(0, 6));  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자)

};

scwin.codeSetGauceUtilCallBack = function(){
    acb_copCoConfirmClsCd.addItem("전체", "", "", 0);
    acb_copCoConfirmClsCd.setSelectedIndex(0);

    acb_selpchItemCd.addItem("전체", "", "", 0);
    acb_selpchItemCd.setSelectedIndex(0);

    acb_pchsAdmitClsCd.addItem("전체", "", "", 0);
    acb_pchsAdmitClsCd.setSelectedIndex(0);

    acb_dtCls.setSelectedIndex(1);  // 일자구분
    scwin.f_SelWrkDt();		
    scwin.f_SetDefaultData();				
    $c.gus.cfDisableAllBtn();
    scwin.f_GetChkPchsAmtSum("INIT");

    $p.setTimeout(function() {
        // // 매입부서 : 4A5, 실적일자 : 2007/05/01 ~ 2007/05/31, 매입거래처 : 112595
        // ed_pchsDeptCd.setValue("4A5");
        // ed_pchsDeptCd.focus();
        // ed_pchsDeptCd.blur();
        // // ica_wrkDtSt.setValue("20070501")
        // // ica_wrkDtEnd.setValue("20070531")
        // ica_wrkDtSt.setValue("20250630")
        // ica_wrkDtEnd.setValue("20251231")
        // // ed_pchsClntNo.setValue("112595")
        // ed_pchsClntNo.setValue("999901")
        // ed_pchsClntNo.focus();
        // ed_pchsClntNo.blur();

    }, {"delay":50});


};

scwin.codeSetCommonCodeCallBack = function(){
    const codeOptions2 = [ 
        {
            method: "getLuxeComboData", 
            param1: "LogisticsPurchaseEvidenceEBC", 
            param2: "retriveSelpchItemCdList",
            param3: ["CMP"],
            compID: "acb_selpchItemCd" 
        }
    ];
    $c.data.setGauceUtil(codeOptions2, scwin.codeSetGauceUtilCallBack);

};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {

    }, {"delay":50});
};

//-------------------------------------------------------------------------
// Default Data Setting
//-------------------------------------------------------------------------
scwin.f_SetDefaultData = function () {		
    scwin.f_GetPchsAdmitCntTotAmt();  // 건수/총금액 계산

    ica_copCoConfirmDtSt.setValue(scwin.vQryStDt);      // 업체확인일자시작
    ica_copCoConfirmDtEnd.setValue(scwin.vQryEndDt);    // 업체확인일자종료	
    ica_wrkDtSt.setValue(scwin.vQryStDt);               // 운송일자시작		
    ica_wrkDtEnd.setValue(scwin.vQryEndDt);             // 운송일자종료
    ica_pchsIntendDt.setValue(scwin.vCurDate);          // 매입예정일자		
    // cfSetIMEModeActiveObjects([ed_pchsDeptNm, ed_pchsClntNm, ed_admitPicNm, ed_rmk, ed_pstpnRsn, ed_lineNm]);  // IME 한글 처리
    $c.gus.cfDisableObjects([ica_pchsIntendDt, ed_rmk, ed_certiNo, btn_certiNo, ed_hid_rmk, ed_pstpnRsn]);
    acb_copCoConfirmClsCd.setMaxLength(50);		
    acb_copCoConfirmClsCd.setSelectedIndex(0);
    acb_pchsAdmitClsCd.setMaxLength(50);		
    acb_pchsAdmitClsCd.setSelectedIndex(0);
    acb_selpchItemCd.setMaxLength(50);
    acb_selpchItemCd.setSelectedIndex(0);  // 매입항목

    ed_pchsDeptCd.setValue($c.data.getMemInfo("lobranCd"));

    var lobranNm = $c.data.getMemInfo("lobranNm") == null ? "" : $c.data.getMemInfo("lobranNm");
    ed_pchsDeptNm.setValue(lobranNm);	
    ed_pchsDeptCd.focus();		
};

//-------------------------------------------------------------------------
// 하역기타원가승인 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveStevedoringOrthersPrimeCostAdmission = async function () {		
    // 검색조건 필수 입력 체크, 동일 날짜 포함 여부 체크
    if (acb_dtCls.getValue() == "01") {  // 업체확인일자 기준	

        if (!await $c.gus.cfValidate([ed_pchsDeptCd, ed_pchsClntNo, ica_copCoConfirmDtSt, ica_copCoConfirmDtEnd])) {
            return;
        }
        if (!await $c.gus.cfIsAfterDate(ica_copCoConfirmDtSt.getValue(), ica_copCoConfirmDtEnd.getValue())) {
            await $c.gus.cfAlertMsg("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
            ica_copCoConfirmDtSt.focus();
            return;
        }			
    } else if (acb_dtCls.getValue() == "02") {  // 실적일자 기준
        if (!await $c.gus.cfValidate([ed_pchsDeptCd, ed_pchsClntNo, ica_wrkDtSt, ica_wrkDtEnd])) {
            return;
        }

        if (!await $c.gus.cfIsAfterDate(ica_wrkDtSt.getValue(), ica_wrkDtEnd.getValue())) {
            await $c.gus.cfAlertMsg("조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
            ica_wrkDtSt.focus();
            return;
        }
    }	
    // 구분(미확인포함여부/미승인포함여부)- 쿼리문에서 사용
    if (cbx_unconfirmedIncluYn.getValue() == '0' && cbx_unAdmitIncluYn.getValue() == '0') {
        ds_purchaseListQueryConditionDTO.set("incluYn", "N");
    } else {
        ds_purchaseListQueryConditionDTO.set("incluYn", "Y");		
    }	
    scwin.f_GetChkPchsAmtSum("INIT");
    $c.sbm.execute(sbm_purchaseListQueryConditionDTO);
};

//-------------------------------------------------------------------------
// 신규매입승인 등록
//-------------------------------------------------------------------------
scwin.f_NewPurchaseAdmission = async function () {	
    // Data 변경 여부 조회
    var modifyRowCnt = ds_stevedoringOrthersPrimeCostDTOList.getModifiedIndex().length;
    if (!(modifyRowCnt > 0)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["목록"]);  // 선택된 @이(가) 없습니다.
        return;
    }
    // 매입승인구분(FS262)이 02:승인이 아닌 경우
    var copCoConfirmClsCd = "";		
    var pchsAdmitClsCd = "";
    for (var i = 0 ; i < ds_stevedoringOrthersPrimeCostDTOList.getRowCount(); i++) {
        copCoConfirmClsCd = ds_stevedoringOrthersPrimeCostDTOList.getCellData(i, "copCoConfirmClsCd");
        pchsAdmitClsCd = ds_stevedoringOrthersPrimeCostDTOList.getCellData(i, "pchsAdmitClsCd");

        if (ds_stevedoringOrthersPrimeCostDTOList.getCellData(i, "chk") == "T") {
            // if (copCoConfirmClsCd != "02") {
            // 	await $c.gus.cfAlertMsg("업체확인이 확인인 경우만 가능합니다.");
            // 	return;
            // }		
            if (pchsAdmitClsCd == "02") {	
                await $c.gus.cfAlertMsg("매입승인이 미승인, 보류인 경우만 가능합니다.");
                return;
            }		
        }
    }
    // 매입예정일자 체크
    if (!await $c.gus.cfValidate([ica_pchsIntendDt])) {
        return;
    }		
    if (await $c.win.confirm(MSG_CM_CRM_001)) {  // 저장하시겠습니까?		
        ds_purchaseCerti.set("selpchItemCd", acb_selpchItemCd.getValue());  // 매출입항목코드
        //ds_purchaseCerti.NameValue(ds_purchaseCerti.RowPosition, "pchsGoodsPatternCd") = "09";  // 매입품목유형코드(기타)
        $c.sbm.execute(sbm_saveRegistNewPurchaseAdmission);

    }
};

//-------------------------------------------------------------------------
// 추가매입승인 등록
//-------------------------------------------------------------------------
scwin.f_AdditionPurchaseAdmission = async function () {
    // Data 변경 여부 조회
    var modifyRowCnt = ds_stevedoringOrthersPrimeCostDTOList.getModifiedIndex().length;
    if (!(modifyRowCnt > 0)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["목록"]);  // 선택된 @이(가) 없습니다.
        return;
    }
    // 매입승인구분(FS262)이 02:승인이 아닌 경우
    var copCoConfirmClsCd = "";
    var pchsAdmitClsCd = "";
    for (var i = 0 ; i < ds_stevedoringOrthersPrimeCostDTOList.getRowCount(); i++) {
        copCoConfirmClsCd = ds_stevedoringOrthersPrimeCostDTOList.getCellData(i, "copCoConfirmClsCd");
        pchsAdmitClsCd = ds_stevedoringOrthersPrimeCostDTOList.getCellData(i, "pchsAdmitClsCd");
        if (ds_stevedoringOrthersPrimeCostDTOList.getCellData(i, "chk") == "T") {
            // if (copCoConfirmClsCd != "02") {
            // 	await $c.gus.cfAlertMsg("업체확인이 확인인 경우만 가능합니다.");
            // 	return;
            // }		
            if (pchsAdmitClsCd == "02") {	
                await $c.gus.cfAlertMsg("매입승인이 미승인, 보류인 경우만 가능합니다.");
                return;
            }		
        }
    }		
    // 거래명세서번호 체크
    if (!await $c.gus.cfValidate([ed_certiNo])) {
        return;
    }
    if (await $c.win.confirm(MSG_CM_CRM_001)) {  // 저장하시겠습니까?	
        ds_purchaseCerti.set("selpchItemCd", acb_selpchItemCd.getValue());  // 매출입항목코드
        //ds_purchaseCerti.NameValue(ds_purchaseCerti.RowPosition, "pchsGoodsPatternCd") = "09";  // 매입품목유형코드(기타)
        $c.sbm.execute(sbm_saveRegistAdditionPurchaseAdmission);	    
    }
};

//-------------------------------------------------------------------------
// 매입승인보류 등록
//-------------------------------------------------------------------------
scwin.f_PurchasePostpone = async function () {
    // Data 변경 여부 조회
    var modifyRowCnt = ds_stevedoringOrthersPrimeCostDTOList.getModifiedIndex().length;
    if (!(modifyRowCnt > 0)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["목록"]);  // 선택된 @이(가) 없습니다.
        return;
    }
    // 매입승인구분(FS262)이 01:미승인인 경우
    var pchsAdmitClsCd = "";
    for (var i = 0 ; i < ds_stevedoringOrthersPrimeCostDTOList.getRowCount(); i++) {		
        pchsAdmitClsCd = ds_stevedoringOrthersPrimeCostDTOList.getCellData(i, "pchsAdmitClsCd");

        if (ds_stevedoringOrthersPrimeCostDTOList.getCellData(i, "chk") == "T") {	
            if (pchsAdmitClsCd != "01") {	
                await $c.gus.cfAlertMsg("매입승인이 미승인인 경우만 가능합니다.");
                return;
            }		
        }
    }		
    // 보류사유 체크
    if (!await $c.gus.cfValidate([ed_pstpnRsn])) {
        return;
    }
    if (await $c.win.confirm(MSG_CM_CRM_001)) {  // 저장하시겠습니까?		
        $c.sbm.execute(sbm_saveRegistPurchasePostpone);		    
    }
};

//-------------------------------------------------------------------------
// 매입승인취소 등록
//-------------------------------------------------------------------------
scwin.f_PurchaseAdmissionCancel = async function () {	
    // Data 변경 여부 조회
    var modifyRowCnt = ds_stevedoringOrthersPrimeCostDTOList.getModifiedIndex().length;
    if (!(modifyRowCnt > 0)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["목록"]);  // 선택된 @이(가) 없습니다.
        return;
    }

    // 매입승인구분(FS262)이 02:승인인 경우와 매입확정 이전인 경우
    var pchsAdmitClsCd = "";
    var pchsEvidYn = "";		
    for (var i = 0 ; i < ds_stevedoringOrthersPrimeCostDTOList.getRowCount(); i++) {		
        pchsAdmitClsCd = ds_stevedoringOrthersPrimeCostDTOList.getCellData(i, "pchsAdmitClsCd");
        pchsEvidYn = ds_stevedoringOrthersPrimeCostDTOList.getCellData(i, "x");
        if (ds_stevedoringOrthersPrimeCostDTOList.getCellData(i, "chk") == "T") {	
            if (pchsAdmitClsCd != "02") {	
                await $c.gus.cfAlertMsg("매입승인이 승인인 경우만 가능합니다.");
                return;
            }	
            if (pchsEvidYn == "Y") {	
                await $c.gus.cfAlertMsg("매입확정 이전인 경우만 가능합니다.");
                return;
            }					
        }
    }				
    if (await $c.win.confirm(MSG_CM_CRM_001)) {  // 저장하시겠습니까?	
        $c.sbm.execute(sbm_saveRegistPurchaseAdmissionCancel);		    
    }
}

//-------------------------------------------------------------------------
// 거래명세서번호 검색
//------------------------------------------------------------------------- 
scwin.f_OpenCertiNoPopUp = async function () {
    var args = new Array();
    if (ds_stevedoringOrthersPrimeCostDTOList.getRowCount()	== 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        return;
    }
    if (!await $c.gus.cfValidate([ed_pchsDeptCd, ed_pchsClntNo])) {
        return;
    }		
    args["pchsDeptCd"] = ed_pchsDeptCd.getValue();  // 매입부서
    args["pchsClntNo"] = ed_pchsClntNo.getValue();  // 매입거래처
    args["selpchItemCd"] = acb_selpchItemCd.getValue();  // 매출입항목코드
    args["pchsGoodsPatternCd"] = "";  // 매입품목유형코드

    var min = ds_stevedoringOrthersPrimeCostDTOList.getColMin("rsltsStdDt").toString();
    var max = ds_stevedoringOrthersPrimeCostDTOList.getColMax("rsltsStdDt").toString();
    args["pchsIntendDtSt"]  = min.substring(0, 6) + "01";  // 운송일자 Min(특정일자의 첫번째 날 리턴)
    args["pchsIntendDtEnd"] = max.substring(0, 6) + $c.date.getLastDateOfMonth(max.substring(0, 6));  // 운송일자 Max(특정일자의 마지막 날 리턴)

    var data = {
        "pchsDeptCd" : ed_pchsDeptCd.getValue()  // 매입부서
        , "pchsClntNo" : ed_pchsClntNo.getValue()  // 매입거래처
        , "selpchItemCd" : acb_selpchItemCd.getValue()  // 매출입항목코드
        , "pchsGoodsPatternCd" : ""  // 매입품목유형코드
        , "pchsIntendDtSt" : min.substring(0, 6) + "01"  // 운송일자 Min(특정일자의 첫번째 날 리턴)
        , "pchsIntendDtEnd" : max.substring(0, 6) + $c.date.getLastDateOfMonth(max.substring(0, 6))  // 운송일자 Max(특정일자의 마지막 날 리턴)
    };
    // var popupResult = window.showModalDialog('/ds/fs/adjm/fs_102_01_16p.jsp?paramTitle=거래명세서번호 검색',args,"dialogWidth:500px;dialogHeight:550px;status:No");
    let win_url = "/ui/ds/fs/adjm/fs_102_01_16p.xml";
    let opts = {
        id : "certiNoPop"
        , popupName : "거래명세서번호 검색"
        , modal : true
        , type : "browserPopup"
        , width : 840
        , height : 714
        , title : "거래명세서번호 검색"
    };
    var popupResult = await $c.win.openPopup(win_url, opts, data);
    // Modal Dialog를 리턴값 없이 닫을 경우에 대비해
    if (popupResult != null) {
        ed_certiNo.setValue(popupResult.certiNo);
        ed_hid_rmk.setValue(popupResult.rmk);
    }	    
}; 	

//-------------------------------------------------------------------------
// 조회건수/조회총금액, 매입승인건수/매입승인총금액 계산
//------------------------------------------------------------------------- 
scwin.f_GetPchsAdmitCntTotAmt = function () {
    // 기타 원가	
    var qryCnt = 0;
    var qryTotAmt = 0;

    if (ds_stevedoringOrthersPrimeCostDTOList.getRowCount() > 0) {
        qryCnt = ds_stevedoringOrthersPrimeCostDTOList.getRowCount();	
        qryTotAmt = 0;	
        for (var i = 0; i < qryCnt; i++){
            qryTotAmt += parseInt(ds_stevedoringOrthersPrimeCostDTOList.getCellData(i, "pchsAmt"));
        }
    }
    txt_qryCnt.setStyle("color", "blue");
    txt_qryCnt.setValue($c.gus.cfInsertComma(qryCnt));		
    txt_qryTotAmt.setStyle("color", "blue");
    txt_qryTotAmt.setValue($c.gus.cfInsertComma(qryTotAmt));

    // 매입승인구분이 승인(02)인 경우만 해송임 계산		
    var pchsAdmitCnt = 0;
    var pchsAdmitTotAmt = 0;
    for (var i = 0 ; i < ds_stevedoringOrthersPrimeCostDTOList.getRowCount(); i++) {
        if (ds_stevedoringOrthersPrimeCostDTOList.getCellData(i, "pchsAdmitClsCd") == "02") {
            pchsAdmitTotAmt += parseInt(ds_stevedoringOrthersPrimeCostDTOList.getCellData(i, "pchsAmt"));
            pchsAdmitCnt++;
        }
    }
    txt_pchsAdmitCnt.setStyle("color", "blue");
    txt_pchsAdmitCnt.setValue($c.gus.cfInsertComma(pchsAdmitCnt));
    txt_pchsAdmitTotAmt.setStyle("color", "blue");
    txt_pchsAdmitTotAmt.setValue($c.gus.cfInsertComma(pchsAdmitTotAmt));
};	

//-------------------------------------------------------------------------
// 선택금액 합계 계산
//------------------------------------------------------------------------- 
scwin.f_GetChkPchsAmtSum = function (cls) {
    var chkPchsAmtSum = 0;
    var chkVatAmtSum = 0;

    if (cls != "INIT") {
        var totRowCnt = ds_stevedoringOrthersPrimeCostDTOList.getRowCount();
        for(var i = 0 ; i < totRowCnt ; i++) {
            var chk = ds_stevedoringOrthersPrimeCostDTOList.getCellData(i, "chk");
            if (chk == "T") {
                chkPchsAmtSum += parseInt(ds_stevedoringOrthersPrimeCostDTOList.getCellData(i, "pchsAmt"));
                chkVatAmtSum += parseInt(ds_stevedoringOrthersPrimeCostDTOList.getCellData(i, "vat"));
            }
        }
    }
    txt_chkPchsAmtSum.setStyle("color", "blue");
    txt_chkPchsAmtSum.setValue($c.gus.cfInsertComma(chkPchsAmtSum));
    txt_chkVatAmtSum.setStyle("color", "blue");
    txt_chkVatAmtSum.setValue($c.gus.cfInsertComma(chkVatAmtSum));
};

//-------------------------------------------------------------------------
// 업체확인일자 선택
//------------------------------------------------------------------------- 
scwin.f_SelCopCoConfirmDt = function () {
    udc_copCoConfirmDt.show();      // lay_gubun1
    acb_copCoConfirmClsCd.hide();   // lay_gubun2
    txt_copCoConfirmCls.hide();
    acb_pchsAdmitClsCd.show();      // lay_gubun3
    udc_wrkDt.hide();               // lay_gubun4
    cbx_unconfirmedIncluYn.hide();  // lay_gubun5
    cbx_unAdmitIncluYn.show();      // lay_gubun6

    // lay_gubun1.style.display = "block";
    // lay_gubun2.style.display = "none";
    // lay_gubun3.style.position = "relative";  // 매입승인구분 위치 가변
