        //                                                         + "skiprow:1;");       // 타이틀 다음 떼는 로우 수
        // // cfGridToExcel(그리드ID, "엑셀 파일의 쉬트명", "엑셀 파일명", 저장 옵션);
        // cfGridToExcel(gr_stevedoringOrthersPrimeCostDTOList, "기타원가 매입 승인", "기타원가 매입 승인.xls", 4 + 8 + 16);

        // * @param {Array} infoArr						subTotalFontName 그리드에 대한 내용을 추가로 다른 셀에 표현하는 경우 사용하는 배열
        // * @param {Number} infoArr.rowIndex			표시할 행번호
        // * @param {Number} infoArr.colIndex			표시할 열번호
        // * @param {Number} infoArr.rowSpan			행의 수
        // * @param {Number} infoArr.colSpan			열의 수
        // * @param {String} infoArr.text				내용
        // * @param {String} infoArr.textAlign			표시할 내용의 정렬 방법 (left, center, right)
        // * @param {String} infoArr.fontSize			font size 설정 ( ex) "20px" )
        // * @param {String} infoArr.fontName			font name 설정
        // * @param {String} infoArr.color				font color 설정 ( ex) "red" )
        // * @param {String} infoArr.fontWeight			font weight 설정 ( ex) "bold" )
        // * @param {String} infoArr.drawBorder			cell의 border 지정 ( ex) true )
        // * @param {String} infoArr.borderColor		cell의 border color를 지정 ( ex) "#FF0000", "red" )
        // * @param {String} infoArr.borderWidth		cell의 border width 지정 ( "thin", "medium", "thick" )
        // * @param {String} infoArr.wordWrap			cell의 줄 바꿈 기능 ( ex) "true" )
        // * @param {String} infoArr.bgColor			cell의 배경 color 설정 ( ex) "red" )
        // * 

        var argGridTotalCol = 0;
        for (var i = 0 ; i < gr_stevedoringOrthersPrimeCostDTOList.getTotalCol(); i++) {
            if (gr_stevedoringOrthersPrimeCostDTOList.getColumnVisible(i)) {
                argGridTotalCol++;
            }
        }

        const infoArr = [{
              rowIndex    : 0
            , colIndex    : 0
            , rowSpan     : 1
            , colSpan     : argGridTotalCol
            , text        : "기타원가 매입 승인"
            , textAlign   : "center"
            // , fontSize    : "12pt"
            , fontName    : "돋움체"
            , color       : "black"
            , fontWeight  : ""
            , drawBorder  : "false"
            , borderColor : ""
            , borderWidth : ""
            , wordWrap    : "true"
            , bgColor     : "#ffffff"
        }];
        const options = {
            fileName : "기타원가 매입 승인.xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
            sheetName: "기타원가 매입 승인",
            startRowIndex: 2,
        };
        $c.data.downloadGridViewExcel(gr_stevedoringOrthersPrimeCostDTOList, options, infoArr);
    }
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    switch (disGubun) {
        case 1:  			
            // 점소 팝업
            udc_pchsDept.setSelectId('retrieveLobranInfo');			
            udc_pchsDept.cfCommonPopUp(scwin.udc_pchsDept_callBackFunc
                                      ,pCode.trim()
                                      ,pName
                                      ,pClose
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,pAllSearch
                                      ,null
            );	  				  			
            break;
        case 2:
            // 협력회사 팝업			
            udc_pchsClnt.setSelectId('retrieveClntList');
            udc_pchsClnt.cfCommonPopUp(scwin.udc_pchsClnt_callBackFunc
                                      ,pCode.trim()
                                      ,pName
                                      ,pClose
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,pAllSearch
                                      ,null
            );
            break;		
        case 3:
            // 승인담당자 팝업			
            udc_admitPic.setSelectId('retrieveEmpInfo');
            udc_admitPic.cfCommonPopUp(scwin.udc_admitPic_callBackFunc
                                      ,pCode.trim()
                                      ,pName
                                      ,pClose
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,null
                                      ,pAllSearch
                                      ,null
            );	  				  			
            break;
        case 4:
            // LINE코드 팝업
            udc_line.setSelectId('retrieveLineInfo');
            udc_line.cfCommonPopUp(scwin.udc_line_callBackFunc
                                  ,pCode.trim()
                                  ,pName
                                  ,pClose
                                  ,null
                                  ,null
                                  ,null
                                  ,null
                                  ,null
                                  ,null
                                  ,null
                                  ,null
                                  ,null
                                  ,null
                                  ,pAllSearch
                                  ,null
            );
            break;
        default:
            break;
    }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {

  	// 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  	if (!await $c.gus.cfCanOpenPopup(inObj, pairObj)) return;

	// 짝이 되는 오브젝트의 값 제거
	$c.gus.cfClearPairObj(pairObj);

	// 검색어 세팅
	var pVal = $c.gus.cfGetValue(inObj);

	// inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
	    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
	else
	    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

