scwin.sbm_purchaseListQueryConditionDTO_submitdone = async function (e) {
    // 총 조회건수 표시
    var totalRow = ds_stevedoringOrthersPrimeCostDTOList.getRowCount();
    txt_totalRows.setValue(totalRow);

    // 건수/총금액 계산
    scwin.f_GetPchsAdmitCntTotAmt();

    // gr_stevedoringOrthersPrimeCostDTOList.ColumnProp('chk','HeadCheck') = "false";
    gr_stevedoringOrthersPrimeCostDTOList.setHeaderValue("hd_chk", "0");
    ica_pchsIntendDt.getValue(scwin.vCurDate); // 매입예정일자

    if (acb_dtCls.getValue() == "02") {
        ica_pchsIntendDt.setValue(ica_wrkDtEnd.getValue());
    }
    ed_rmk.setValue(""); // 비고
    ed_certiNo.setValue(""); // 거래명세서번호
    ed_hid_rmk.setValue("");  // 비고		
    ed_pstpnRsn.setValue(""); // 보류사유

    if (totalRow == 0) {
        $c.gus.cfDisableAllBtn();		
        $c.gus.cfDisableObjects([ica_pchsIntendDt, ed_rmk, ed_certiNo, btn_certiNo, ed_hid_rmk, ed_pstpnRsn]);
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);  // 해당되는 자료가 존재하지 않습니다
    } else {
        $c.gus.cfEnableAllBtn();		
        $c.gus.cfEnableObjects([ica_pchsIntendDt, ed_rmk, btn_certiNo, ed_pstpnRsn]);
    }
};

